<?php
namespace App\Http\Controllers\Api;
use App\Domain\Repayments\Actions\RestructureLoan;use App\Enums\RepaymentFrequency;use App\Http\Controllers\Controller;use App\Models\Loan;use App\Models\LoanRestructure;use Illuminate\Http\JsonResponse;use Illuminate\Http\Request;use Illuminate\Validation\Rule;
class LoanRestructureController extends Controller{public function store(Request $request,Loan $loan,RestructureLoan $action):JsonResponse{$d=$request->validate(['reason'=>['required','string','max:3000'],'capitalized_arrears_minor'=>['sometimes','integer','min:0'],'new_interest_rate_basis_points'=>['nullable','integer','between:0,100000'],'new_repayment_frequency'=>['nullable',Rule::enum(RepaymentFrequency::class)],'new_tenure'=>['required','integer','between:1,600'],'new_start_date'=>['required','date']]);return response()->json($action->request($loan,$d),201);}public function decide(Request $request,LoanRestructure $restructure,RestructureLoan $action):JsonResponse{$d=$request->validate(['decision'=>['required','in:approve,reject'],'reason'=>['required','string','max:2000']]);return response()->json($action->decide($restructure,$d['decision'],$d['reason']));}public function apply(LoanRestructure $restructure,RestructureLoan $action):JsonResponse{return response()->json($action->apply($restructure));}}
